import subprocess
import os

def convertDocument(input_file, output_file, format_type):
    # Get the absolute path of input file
    input_path = os.path.abspath(input_file)
    
    # Get the absolute path of output file
    output_path = os.path.abspath(output_file)
    
    # Get the directory of output file
    output_dir = os.path.dirname(output_path)
    
    # Create output directory if it doesn't exist
    if not os.path.exists(output_dir):
        os.makedirs(output_dir)
    
    # Build the LibreOffice command
    cmd = [
        'libreoffice',
        '--headless',
        '--convert-to',
        format_type,
        '--outdir',
        output_dir,
        input_path
    ]
    
    try:
        # Execute the command
        result = subprocess.run(cmd, capture_output=True, text=True, check=True)
        return True
    except subprocess.CalledProcessError as e:
        print(f"Error converting document: {e}")
        return False
    except FileNotFoundError:
        print("Error: LibreOffice not found. Please install LibreOffice and ensure it's in your PATH.")
        return False